"use strict";parserFactory.register("shintranslations.com",()=>new ShintranslationsParser);class ShintranslationsParser extends Parser{constructor(){super()}async getChapterUrls(r){return[...r.querySelectorAll("div.text-formatting a")].map(r=>util.hyperLinkToChapter(r))}findContent(r){return r.querySelector("div.content-area")}}